     1→/**
     2→ * Game of Thrones Theme for The Game of Chess
     3→ * Defines colors, symbols, and visual styling for GoT themed chess
     4→ */
     5→
     6→const GoTTheme = {
     7→    // Color palette
     8→    colors: {
     9→        // Board colors
    10→        boardDark: '#2d3436',
    11→        boardLight: '#636e72',
    12→        boardBorder: '#c9a227',
    13→
    14→        // White pieces (Noble Houses)
    15→        whitePrimary: '#b0bec5',
    16→        whiteSecondary: '#4a4a4a',
    17→        whiteAccent: '#1e3a5f', // Stark blue
    18→        whiteGlow: 'rgba(30, 58, 95, 0.3)',
    19→
    20→        // Black pieces (White Walkers)
    21→        blackPrimary: '#e3f2fd',
    22→        blackSecondary: '#0288d1',
    23→        blackAccent: '#4fc3f7', // Ice blue
    24→        blackGlow: 'rgba(79, 195, 247, 0.4)',
    25→
    26→        // UI highlights
    27→        highlightValid: 'rgba(76, 175, 80, 0.5)',
    28→        highlightSelected: 'rgba(255, 193, 7, 0.6)',
    29→        highlightCheck: 'rgba(244, 67, 54, 0.7)',
    30→        highlightLastMove: 'rgba(155, 89, 182, 0.4)',
    31→
    32→        // Special colors
    33→        targaryenRed: '#8b0000',
    34→        lannisterGold: '#c9a227',
    35→        nightKingBlue: '#01579b'
    36→    },
    37→
    38→    // Piece symbols (heraldic/GoT themed)
    39→    pieceSymbols: {
    40→        white: {
    41→            pawn: '🛡️',      // Shield
    42→            rook: '🏰',       // Castle/Tower
    43→            knight: '🐺',     // Direwolf (Stark)
    44→            bishop: '🌲',     // Weirwood tree
    45→            queen: '🐉',      // Dragon (Targaryen)
    46→            king: '👑'        // Iron Throne crown
    47→        },
    48→        black: {
    49→            pawn: '❄️',       // Snowflake
    50→            rook: '🧊',       // Ice block
    51→            knight: '💀',     // Skull
    52→            bishop: '👁️',     // Night King eye
    53→            queen: '🌨️',      // Blizzard
    54→            king: '🧛'        // Night King
    55→        }
    56→    },
    57→
    58→    // Alternative piece symbols (unicode chess pieces for fallback)
    59→    chessSymbols: {
    60→        white: {
    61→            pawn: '♙', rook: '♖', knight: '♘', bishop: '♗', queen: '♕', king: '♔'
    62→        },
    63→        black: {
    64→            pawn: '♟', rook: '♜', knight: '♞', bishop: '♝', queen: '♛', king: '♚'
    65→        }
    66→    },
    67→
    68→    // House banners for decoration
    69→    houses: {
    70→        stark: { name: 'Stark', color: '#1e3a5f', symbol: '🐺' },
    71→        lannister: { name: 'Lannister', color: '#c9a227', symbol: '🦁' },
    72→        targaryen: { name: 'Targaryen', color: '#8b0000', symbol: '🐉' },
    73→        baratheon: { name: 'Baratheon', color: '#2d3436', symbol: '🦌' },
    74→        nightKing: { name: 'Night King', color: '#01579b', symbol: '🧛' }
    75→    },
    76→
    77→    // Board texture patterns
    78→    patterns: {
    79→        // Dark square pattern - stone texture
    80→        darkSquare: (ctx, x, y, size) => {
    81→            // Base color
    82→            ctx.fillStyle = '#2d3436';
    83→            ctx.fillRect(x, y, size, size);
    84→
    85→            // Add subtle texture
    86→            ctx.fillStyle = 'rgba(0, 0, 0, 0.1)';
    87→            for (let i = 0; i < 5; i++) {
    88→                const px = x + Math.random() * size;
    89→                const py = y + Math.random() * size;
    90→                ctx.beginPath();
    91→                ctx.arc(px, py, 1 + Math.random() * 2, 0, Math.PI * 2);
    92→                ctx.fill();
    93→            }
    94→
    95→            // Add frost pattern for black side
    96→            ctx.strokeStyle = 'rgba(79, 195, 247, 0.1)';
    97→            ctx.lineWidth = 1;
    98→            ctx.beginPath();
    99→            ctx.moveTo(x + size * 0.2, y + size * 0.8);
   100→            ctx.lineTo(x + size * 0.5, y + size * 0.5);
   101→            ctx.lineTo(x + size * 0.8, y + size * 0.2);
   102→            ctx.stroke();
   103→        },
   104→
   105→        // Light square pattern - weathered wood
   106→        lightSquare: (ctx, x, y, size) => {
   107→            // Base color
   108→            ctx.fillStyle = '#636e72';
   109→            ctx.fillRect(x, y, size, size);
   110→
   111→            // Add wood grain texture
   112→            ctx.strokeStyle = 'rgba(0, 0, 0, 0.05)';
   113→            ctx.lineWidth = 1;
   114→            for (let i = 0; i < 3; i++) {
