   432→            board: this.board.getState(),
   433→            currentTurn: this.currentTurn,
   434→            gameState: this.gameState,
   435→            moveHistory: this.moveHistory,
   436→            capturedPieces: this.capturedPieces.map(p => ({
   437→                color: p.color,
   438→                type: p.type
   439→            }))
   440→        };
