     1→/**
     2→ * Canvas renderer for the chess board
     3→ * Handles all drawing operations for the game
     4→ */
     5→
     6→class Renderer {
     7→    constructor(canvas, board) {
     8→        this.canvas = canvas;
     9→        this.ctx = canvas.getContext('2d');
    10→        this.board = board;
    11→        this.squareSize = canvas.width / 8;
    12→        this.selectedSquare = null;
    13→        this.validMoves = [];
    14→        this.lastMove = null;
    15→        this.animationManager = new AnimationManager();
    16→        this.checkAnimation = null;
    17→        this.gameOverAnimation = null;
    18→        this.hoveredSquare = null;
    19→    }
    20→
    21→    /**
    22→     * Render the entire board
    23→     */
    24→    render() {
    25→        this.clearCanvas();
    26→        this.drawBoard();
    27→        this.drawHighlights();
    28→        this.drawPieces();
    29→        this.drawAnimations();
    30→        this.drawDecorations();
    31→    }
    32→
    33→    /**
    34→     * Clear the canvas
    35→     */
    36→    clearCanvas() {
    37→        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    38→    }
    39→
    40→    /**
    41→     * Draw the board squares
    42→     */
    43→    drawBoard() {
    44→        for (let row = 0; row < 8; row++) {
    45→            for (let col = 0; col < 8; col++) {
    46→                const x = col * this.squareSize;
    47→                const y = row * this.squareSize;
    48→                const isDark = (row + col) % 2 === 1;
    49→
    50→                if (isDark) {
    51→                    GoTTheme.patterns.darkSquare(this.ctx, x, y, this.squareSize);
    52→                } else {
    53→                    GoTTheme.patterns.lightSquare(this.ctx, x, y, this.squareSize);
    54→                }
    55→            }
    56→        }
    57→    }
    58→
    59→    /**
    60→     * Draw highlights (selected, valid moves, check, etc.)
    61→     */
    62→    drawHighlights() {
    63→        // Highlight last move
    64→        if (this.lastMove) {
    65→            GoTTheme.drawHighlight(
    66→                this.ctx,
    67→                this.lastMove.from.col * this.squareSize,
    68→                this.lastMove.from.row * this.squareSize,
    69→                this.squareSize,
    70→                'lastMove'
    71→            );
    72→            GoTTheme.drawHighlight(
    73→                this.ctx,
    74→                this.lastMove.to.col * this.squareSize,
    75→                this.lastMove.to.row * this.squareSize,
    76→                this.squareSize,
    77→                'lastMove'
    78→            );
    79→        }
    80→
    81→        // Highlight selected square
    82→        if (this.selectedSquare) {
    83→            GoTTheme.drawHighlight(
    84→                this.ctx,
    85→                this.selectedSquare.col * this.squareSize,
    86→                this.selectedSquare.row * this.squareSize,
    87→                this.squareSize,
    88→                'selected'
    89→            );
    90→        }
    91→
    92→        // Draw valid move indicators
    93→        for (const move of this.validMoves) {
    94→            const x = move.col * this.squareSize;
    95→            const y = move.row * this.squareSize;
    96→
    97→            const targetPiece = this.board.getPieceAt(move.row, move.col);
    98→            const isCapture = targetPiece !== null || move.isEnPassant;
    99→
   100→            GoTTheme.drawMoveIndicator(this.ctx, x, y, this.squareSize, isCapture);
   101→        }
   102→
   103→        // Highlight king if in check
   104→        const gameState = Rules.getGameState(this.board, this.board.currentTurn || 'white');
   105→        if (gameState.inCheck) {
   106→            const kingPos = this.board.findKing(this.board.currentTurn || 'white');
   107→            if (kingPos) {
   108→                GoTTheme.drawHighlight(
   109→                    this.ctx,
   110→                    kingPos.col * this.squareSize,
   111→                    kingPos.row * this.squareSize,
   112→                    this.squareSize,
   113→                    'check'
   114→                );
   115→
   116→                // Draw check alert glow
   117→                if (this.checkAnimation) {
   118→                    this.checkAnimation.drawGlow(
   119→                        this.ctx,
   120→                        kingPos.col * this.squareSize,
   121→                        kingPos.row * this.squareSize,
   122→                        this.squareSize
   123→                    );
   124→                }
   125→            }
   126→        }
   127→    }
   128→
   129→    /**
   130→     * Draw all pieces on the board
   131→     */
   132→    drawPieces() {
   133→        for (let row = 0; row < 8; row++) {
   134→            for (let col = 0; col < 8; col++) {
   135→                const piece = this.board.getPieceAt(row, col);
   136→                if (piece) {
   137→                    // Skip if this piece is being animated
   138→                    const isAnimating = this.animationManager.animations.some(
   139→                        anim => anim.piece === piece && !anim.isComplete
   140→                    );
   141→                    if (isAnimating) continue;
   142→
   143→                    const x = col * this.squareSize;
   144→                    const y = row * this.squareSize;
   145→
   146→                    // Draw hover effect
   147→                    if (this.hoveredSquare &&
   148→                        this.hoveredSquare.row === row &&
   149→                        this.hoveredSquare.col === col) {
   150→                        this.ctx.save();
   151→                        this.ctx.globalAlpha = 0.3;
   152→                        this.ctx.fillStyle = '#c9a227';
   153→                        this.ctx.beginPath();
   154→                        this.ctx.arc(
   155→                            x + this.squareSize / 2,
   156→                            y + this.squareSize / 2,
   157→                            this.squareSize / 2,
   158→                            0, Math.PI * 2
   159→                        );
   160→                        this.ctx.fill();
   161→                        this.ctx.restore();
   162→                    }
   163→
   164→                    GoTTheme.drawPiece(
   165→                        this.ctx,
   166→                        piece.type,
   167→                        piece.color,
   168→                        x, y,
   169→                        this.squareSize
   170→                    );
   171→                }
   172→            }
   173→        }
   174→    }
   175→
   176→    /**
   177→     * Draw active animations
   178→     */
   179→    drawAnimations() {
   180→        for (const animation of this.animationManager.animations) {
   181→            if (animation.draw) {
   182→                animation.draw(this.ctx, this.squareSize);
   183→            }
   184→        }
   185→
   186→        // Draw game over animation
   187→        if (this.gameOverAnimation && !this.gameOverAnimation.isComplete) {
   188→            this.gameOverAnimation.draw(this.ctx, this.canvas.width, this.canvas.height);
   189→        }
   190→    }
   191→
   192→    /**
   193→     * Draw decorative elements
   194→     */
   195→    drawDecorations() {
   196→        // Draw coordinate labels
   197→        this.drawCoordinates();
   198→
   199→        // Draw border
   200→        this.drawBorder();
   201→    }
   202→
   203→    /**
   204→     * Draw coordinate labels (a-h, 1-8)
   205→     */
   206→    drawCoordinates() {
   207→        this.ctx.save();
   208→        this.ctx.font = '12px MedievalSharp';
   209→        this.ctx.fillStyle = '#e3f2fd';
   210→
   211→        // Files (a-h)
   212→        for (let col = 0; col < 8; col++) {
   213→            const file = String.fromCharCode(97 + col);
   214→            const x = col * this.squareSize + this.squareSize - 15;
   215→            this.ctx.fillText(file, x, this.canvas.height - 5);
   216→            this.ctx.fillText(file, x, 12);
   217→        }
   218→
   219→        // Ranks (1-8)
   220→        for (let row = 0; row < 8; row++) {
   221→            const rank = 8 - row;
   222→            const y = row * this.squareSize + this.squareSize - 5;
   223→            this.ctx.fillText(rank.toString(), 5, y);
   224→            this.ctx.fillText(rank.toString(), this.canvas.width - 10, y);
   225→        }
   226→
   227→        this.ctx.restore();
   228→    }
   229→
   230→    /**
   231→     * Draw ornate border
   232→     */
   233→    drawBorder() {
   234→        // Border is handled by CSS, but we can add corner decorations
   235→        this.ctx.save();
   236→        this.ctx.strokeStyle = '#c9a227';
   237→        this.ctx.lineWidth = 2;
   238→
   239→        // Corner ornaments
   240→        const cornerSize = 20;
   241→        const corners = [
   242→            { x: 0, y: 0 },
   243→            { x: this.canvas.width, y: 0 },
   244→            { x: 0, y: this.canvas.height },
   245→            { x: this.canvas.width, y: this.canvas.height }
   246→        ];
   247→
   248→        corners.forEach(corner => {
   249→            this.ctx.beginPath();
