/**
 * Canvas renderer for the chess board
 * Handles all drawing operations for the game
 */

class Renderer {
    constructor(canvas, board) {
        this.canvas = canvas;
        this.ctx = canvas.getContext('2d');
        this.board = board;
        this.squareSize = canvas.width / 8;
        this.selectedSquare = null;
        this.validMoves = [];
        this.lastMove = null;
        this.animationManager = new AnimationManager();
        this.checkAnimation = null;
        this.gameOverAnimation = null;
        this.hoveredSquare = null;
    }

    /**
     * Render the entire board
     */
    render() {
        this.clearCanvas();
        this.drawBoard();
        this.drawHighlights();
        this.drawPieces();
        this.drawAnimations();
        this.drawDecorations();
    }

    /**
     * Clear the canvas
     */
    clearCanvas() {
        this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    }

    /**
     * Draw the board squares
     */
    drawBoard() {
        for (let row = 0; row < 8; row++) {
            for (let col = 0; col < 8; col++) {
                const x = col * this.squareSize;
                const y = row * this.squareSize;
                const isDark = (row + col) % 2 === 1;

                if (isDark) {
                    GoTTheme.patterns.darkSquare(this.ctx, x, y, this.squareSize);
                } else {
                    GoTTheme.patterns.lightSquare(this.ctx, x, y, this.squareSize);
                }
            }
        }
    }

    /**
     * Draw highlights (selected, valid moves, check, etc.)
     */
    drawHighlights() {
        // Highlight last move
        if (this.lastMove) {
            GoTTheme.drawHighlight(
                this.ctx,
                this.lastMove.from.col * this.squareSize,
                this.lastMove.from.row * this.squareSize,
                this.squareSize,
                'lastMove'
            );
            GoTTheme.drawHighlight(
                this.ctx,
                this.lastMove.to.col * this.squareSize,
                this.lastMove.to.row * this.squareSize,
                this.squareSize,
                'lastMove'
            );
        }

        // Highlight selected square
        if (this.selectedSquare) {
            GoTTheme.drawHighlight(
                this.ctx,
                this.selectedSquare.col * this.squareSize,
                this.selectedSquare.row * this.squareSize,
                this.squareSize,
                'selected'
            );
        }

        // Draw valid move indicators
        for (const move of this.validMoves) {
            const x = move.col * this.squareSize;
            const y = move.row * this.squareSize;

            const targetPiece = this.board.getPieceAt(move.row, move.col);
            const isCapture = targetPiece !== null || move.isEnPassant;

            GoTTheme.drawMoveIndicator(this.ctx, x, y, this.squareSize, isCapture);
        }

        // Highlight king if in check
        const gameState = Rules.getGameState(this.board, this.board.currentTurn || 'white');
        if (gameState.inCheck) {
            const kingPos = this.board.findKing(this.board.currentTurn || 'white');
            if (kingPos) {
                GoTTheme.drawHighlight(
                    this.ctx,
                    kingPos.col * this.squareSize,
                    kingPos.row * this.squareSize,
                    this.squareSize,
                    'check'
                );

                // Draw check alert glow
                if (this.checkAnimation) {
                    this.checkAnimation.drawGlow(
                        this.ctx,
                        kingPos.col * this.squareSize,
                        kingPos.row * this.squareSize,
                        this.squareSize
                    );
                }
            }
        }
    }

    /**
     * Draw all pieces on the board
     */
    drawPieces() {
        for (let row = 0; row < 8; row++) {
            for (let col = 0; col < 8; col++) {
                const piece = this.board.getPieceAt(row, col);
                if (piece) {
                    // Skip if this piece is being animated
                    const isAnimating = this.animationManager.animations.some(
                        anim => anim.piece === piece && !anim.isComplete
                    );
                    if (isAnimating) continue;

                    const x = col * this.squareSize;
                    const y = row * this.squareSize;

                    // Draw hover effect
                    if (this.hoveredSquare &&
                        this.hoveredSquare.row === row &&
                        this.hoveredSquare.col === col) {
                        this.ctx.save();
                        this.ctx.globalAlpha = 0.3;
                        this.ctx.fillStyle = '#c9a227';
                        this.ctx.beginPath();
                        this.ctx.arc(
                            x + this.squareSize / 2,
                            y + this.squareSize / 2,
                            this.squareSize / 2,
                            0, Math.PI * 2
                        );
                        this.ctx.fill();
                        this.ctx.restore();
                    }

                    GoTTheme.drawPiece(
                        this.ctx,
                        piece.type,
                        piece.color,
                        x, y,
                        this.squareSize
                    );
                }
            }
        }
    }

    /**
     * Draw active animations
     */
    drawAnimations() {
        for (const animation of this.animationManager.animations) {
            if (animation.draw) {
                animation.draw(this.ctx, this.squareSize);
            }
        }

        // Draw game over animation
        if (this.gameOverAnimation && !this.gameOverAnimation.isComplete) {
            this.gameOverAnimation.draw(this.ctx, this.canvas.width, this.canvas.height);
        }
    }

    /**
     * Draw decorative elements
     */
    drawDecorations() {
        // Draw coordinate labels
        this.drawCoordinates();

        // Draw border
        this.drawBorder();
    }

    /**
     * Draw coordinate labels (a-h, 1-8)
     */
    drawCoordinates() {
        this.ctx.save();
        this.ctx.font = '12px MedievalSharp';
        this.ctx.fillStyle = '#e3f2fd';

        // Files (a-h)
        for (let col = 0; col < 8; col++) {
            const file = String.fromCharCode(97 + col);
            const x = col * this.squareSize + this.squareSize - 15;
            this.ctx.fillText(file, x, this.canvas.height - 5);
            this.ctx.fillText(file, x, 12);
        }

        // Ranks (1-8)
        for (let row = 0; row < 8; row++) {
            const rank = 8 - row;
            const y = row * this.squareSize + this.squareSize - 5;
            this.ctx.fillText(rank.toString(), 5, y);
            this.ctx.fillText(rank.toString(), this.canvas.width - 10, y);
        }

        this.ctx.restore();
    }

    /**
     * Draw ornate border
     */
    drawBorder() {
        // Border is handled by CSS, but we can add corner decorations
        this.ctx.save();
        this.ctx.strokeStyle = '#c9a227';
        this.ctx.lineWidth = 2;

        // Corner ornaments
        const cornerSize = 20;
        const corners = [
            { x: 0, y: 0 },
            { x: this.canvas.width, y: 0 },
            { x: 0, y: this.canvas.height },
            { x: this.canvas.width, y: this.canvas.height }
        ];

        corners.forEach(corner => {
            this.ctx.beginPath();
            this.ctx.moveTo(corner.x, corner.y + cornerSize);
            this.ctx.lineTo(corner.x, corner.y);
            this.ctx.lineTo(corner.x + cornerSize, corner.y);
            this.ctx.stroke();
        });

        this.ctx.restore();
    }

    /**
     * Set selected square
     * @param {Object} square - {row, col} or null
     */
    setSelectedSquare(square) {
        this.selectedSquare = square;
    }

    /**
     * Set valid moves to highlight
     * @param {Array} moves - Array of {row, col} positions
     */
    setValidMoves(moves) {
        this.validMoves = moves || [];
    }

    /**
     * Set last move for highlighting
     * @param {Object} move - {from: {row, col}, to: {row, col}} or null
     */
    setLastMove(move) {
        this.lastMove = move;
    }

    /**
     * Set hovered square
     * @param {Object} square - {row, col} or null
     */
    setHoveredSquare(square) {
        this.hoveredSquare = square;
    }

    /**
     * Animate piece move
     * @param {Object} from - {row, col}
     * @param {Object} to - {row, col}
     * @param {Piece} piece - Piece being moved
     * @returns {Promise} Resolves when animation completes
     */
    async animateMove(from, to, piece) {
        const fromX = from.col * this.squareSize;
        const fromY = from.row * this.squareSize;
        const toX = to.col * this.squareSize;
        const toY = to.row * this.squareSize;

        const animation = new PieceMoveAnimation(fromX, fromY, toX, toY, piece);
        this.animationManager.add(animation);

        return new Promise(resolve => {
            animation.onComplete = resolve;
        });
    }

    /**
     * Animate piece capture
     * @param {Object} pos - {row, col}
     * @param {Piece} piece - Captured piece
     * @returns {Promise} Resolves when animation completes
     */
    async animateCapture(pos, piece) {
        const x = pos.col * this.squareSize;
        const y = pos.row * this.squareSize;

        const animation = new CaptureAnimation(x, y, piece);
        this.animationManager.add(animation);

        return new Promise(resolve => {
            animation.onComplete = resolve;
        });
    }

    /**
     * Trigger check alert animation
     */
    triggerCheckAlert() {
        if (this.checkAnimation && !this.checkAnimation.isComplete) {
            return;
        }

        this.checkAnimation = new CheckAlertAnimation();
        this.animationManager.add(this.checkAnimation);
    }

    /**
     * Trigger game over animation
     * @param {string} winner - 'white' or 'black'
     * @returns {Promise} Resolves when animation completes
     */
    async triggerGameOver(winner) {
        this.gameOverAnimation = new GameOverAnimation(winner);
        this.animationManager.add(this.gameOverAnimation);

        return new Promise(resolve => {
            this.gameOverAnimation.onComplete = resolve;
        });
    }

    /**
     * Convert canvas coordinates to board position
     * @param {number} x - Canvas x coordinate
     * @param {number} y - Canvas y coordinate
     * @returns {Object} Board position {row, col}
     */
    canvasToBoard(x, y) {
        const rect = this.canvas.getBoundingClientRect();
        const scaleX = this.canvas.width / rect.width;
        const scaleY = this.canvas.height / rect.height;

        const canvasX = (x - rect.left) * scaleX;
        const canvasY = (y - rect.top) * scaleY;

        return {
            row: Math.floor(canvasY / this.squareSize),
            col: Math.floor(canvasX / this.squareSize)
        };
    }

    /**
     * Reset the renderer state
     */
    reset() {
        this.selectedSquare = null;
        this.validMoves = [];
        this.lastMove = null;
        this.hoveredSquare = null;
        this.checkAnimation = null;
        this.gameOverAnimation = null;
        this.animationManager.clear();
    }
}

