     1→/**
     2→ * Animation system for smooth piece movements and effects
     3→ */
     4→
     5→class AnimationManager {
     6→    constructor() {
     7→        this.animations = [];
     8→        this.isRunning = false;
     9→        this.lastTime = 0;
    10→    }
    11→
    12→    /**
    13→     * Start the animation loop
    14→     */
    15→    start() {
    16→        if (this.isRunning) return;
    17→        this.isRunning = true;
    18→        this.lastTime = performance.now();
    19→        this.animate();
    20→    }
    21→
    22→    /**
    23→     * Stop the animation loop
    24→     */
    25→    stop() {
    26→        this.isRunning = false;
    27→    }
    28→
    29→    /**
    30→     * Main animation loop
    31→     */
    32→    animate() {
    33→        if (!this.isRunning) return;
    34→
    35→        const currentTime = performance.now();
    36→        const deltaTime = currentTime - this.lastTime;
    37→        this.lastTime = currentTime;
    38→
    39→        // Update all animations
    40→        this.animations = this.animations.filter(animation => {
    41→            animation.update(deltaTime);
    42→            return !animation.isComplete;
    43→        });
    44→
    45→        requestAnimationFrame(() => this.animate());
    46→    }
    47→
    48→    /**
    49→     * Add an animation to the queue
    50→     * @param {Animation} animation - Animation to add
    51→     */
    52→    add(animation) {
    53→        this.animations.push(animation);
    54→        animation.onStart();
    55→
    56→        if (!this.isRunning) {
    57→            this.start();
    58→        }
    59→
    60→        return animation;
    61→    }
    62→
    63→    /**
    64→     * Remove all animations
    65→     */
    66→    clear() {
    67→        this.animations = [];
    68→    }
    69→}
    70→
    71→/**
    72→ * Base Animation class
    73→ */
    74→class Animation {
    75→    constructor(duration) {
    76→        this.duration = duration;
    77→        this.elapsed = 0;
    78→        this.isComplete = false;
    79→        this.onComplete = null;
    80→        this.onStart = null;
    81→    }
    82→
    83→    update(deltaTime) {
    84→        this.elapsed += deltaTime;
    85→
    86→        if (this.elapsed >= this.duration) {
    87→            this.elapsed = this.duration;
    88→            this.isComplete = true;
    89→            if (this.onComplete) {
    90→                this.onComplete();
    91→            }
    92→        }
    93→
    94→        this.apply(this.getProgress());
    95→    }
    96→
    97→    getProgress() {
    98→        return this.elapsed / this.duration;
    99→    }
   100→
   101→    apply(progress) {
   102→        // Override in subclasses
   103→    }
   104→}
   105→
   106→/**
   107→ * Easing functions
   108→ */
   109→const Easing = {
   110→    linear: t => t,
   111→    easeInOutQuad: t => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
   112→    easeOutCubic: t => 1 - Math.pow(1 - t, 3),
   113→    easeOutBounce: t => {
   114→        const n1 = 7.5625;
   115→        const d1 = 2.75;
   116→        if (t < 1 / d1) {
   117→            return n1 * t * t;
   118→        } else if (t < 2 / d1) {
   119→            return n1 * (t -= 1.5 / d1) * t + 0.75;
   120→        } else if (t < 2.5 / d1) {
   121→            return n1 * (t -= 2.25 / d1) * t + 0.9375;
   122→        } else {
   123→            return n1 * (t -= 2.625 / d1) * t + 0.984375;
   124→        }
   125→    }
   126→};
   127→
   128→/**
   129→ * Piece move animation
   130→ */
   131→class PieceMoveAnimation extends Animation {
   132→    constructor(fromX, fromY, toX, toY, piece, duration = 300) {
   133→        super(duration);
   134→        this.fromX = fromX;
   135→        this.fromY = fromY;
   136→        this.toX = toX;
   137→        this.toY = toY;
   138→        this.piece = piece;
   139→        this.currentX = fromX;
   140→        this.currentY = fromY;
   141→    }
   142→
   143→    getProgress() {
   144→        return Easing.easeInOutQuad(this.elapsed / this.duration);
   145→    }
   146→
   147→    apply(progress) {
   148→        this.currentX = this.fromX + (this.toX - this.fromX) * progress;
   149→        this.currentY = this.fromY + (this.toY - this.fromY) * progress;
   150→    }
   151→
   152→    /**
   153→     * Draw the animating piece
   154→     * @param {CanvasRenderingContext2D} ctx - Canvas context
   155→     * @param {number} size - Square size
   156→     */
   157→    draw(ctx, size) {
   158→        if (this.isComplete) return;
   159→
   160→        const x = this.currentX;
   161→        const y = this.currentY;
   162→
   163→        ctx.save();
   164→        ctx.globalAlpha = 0.8;
   165→
   166→        // Draw shadow
   167→        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
   168→        ctx.beginPath();
   169→        ctx.ellipse(
   170→            x + size / 2,
   171→            y + size * 0.85,
   172→            size * 0.3,
   173→            size * 0.1,
   174→            0, 0, Math.PI * 2
   175→        );
   176→        ctx.fill();
   177→
   178→        // Draw piece
   179→        GoTTheme.drawPiece(ctx, this.piece.type, this.piece.color, x, y, size);
   180→
   181→        ctx.restore();
   182→    }
   183→}
   184→
   185→/**
   186→ * Capture animation - pieces exploding/fading
   187→ */
   188→class CaptureAnimation extends Animation {
   189→    constructor(x, y, piece, duration = 400) {
   190→        super(duration);
   191→        this.x = x;
   192→        this.y = y;
   193→        this.piece = piece;
   194→        this.scale = 1;
   195→        this.alpha = 1;
   196→        this.rotation = 0;
   197→        this.particles = this.createParticles();
   198→    }
   199→
   200→    createParticles() {
   201→        const particles = [];
   202→        const particleCount = 10;
   203→
   204→        for (let i = 0; i < particleCount; i++) {
   205→            const angle = (Math.PI * 2 * i) / particleCount;
   206→            const speed = 2 + Math.random() * 3;
   207→            particles.push({
   208→                x: this.x + 40, // Center of square
   209→                y: this.y + 40,
   210→                vx: Math.cos(angle) * speed,
   211→                vy: Math.sin(angle) * speed,
   212→                size: 3 + Math.random() * 5,
   213→                alpha: 1
   214→            });
   215→        }
   216→
   217→        return particles;
   218→    }
   219→
   220→    getProgress() {
   221→        return Easing.easeOutCubic(this.elapsed / this.duration);
   222→    }
   223→
   224→    apply(progress) {
   225→        this.scale = 1 - progress * 0.3;
   226→        this.alpha = 1 - progress;
   227→        this.rotation = progress * Math.PI * 2;
   228→
   229→        // Update particles
   230→        this.particles.forEach(p => {
   231→            p.x += p.vx;
   232→            p.y += p.vy;
   233→            p.alpha = 1 - progress;
   234→        });
   235→    }
   236→
   237→    /**
   238→     * Draw the capture animation
   239→     * @param {CanvasRenderingContext2D} ctx - Canvas context
   240→     * @param {number} size - Square size
   241→     */
   242→    draw(ctx, size) {
   243→        if (this.isComplete) return;
   244→
   245→        ctx.save();
   246→
   247→        // Draw particles
   248→        this.particles.forEach(p => {
   249→            if (p.alpha > 0) {
   250→                ctx.globalAlpha = p.alpha;
