/**
 * Animation system for smooth piece movements and effects
 */

class AnimationManager {
    constructor() {
        this.animations = [];
        this.isRunning = false;
        this.lastTime = 0;
    }

    /**
     * Start the animation loop
     */
    start() {
        if (this.isRunning) return;
        this.isRunning = true;
        this.lastTime = performance.now();
        this.animate();
    }

    /**
     * Stop the animation loop
     */
    stop() {
        this.isRunning = false;
    }

    /**
     * Main animation loop
     */
    animate() {
        if (!this.isRunning) return;

        const currentTime = performance.now();
        const deltaTime = currentTime - this.lastTime;
        this.lastTime = currentTime;

        // Update all animations
        this.animations = this.animations.filter(animation => {
            animation.update(deltaTime);
            return !animation.isComplete;
        });

        requestAnimationFrame(() => this.animate());
    }

    /**
     * Add an animation to the queue
     * @param {Animation} animation - Animation to add
     */
    add(animation) {
        this.animations.push(animation);
        animation.onStart();

        if (!this.isRunning) {
            this.start();
        }

        return animation;
    }

    /**
     * Remove all animations
     */
    clear() {
        this.animations = [];
    }
}

/**
 * Base Animation class
 */
class Animation {
    constructor(duration) {
        this.duration = duration;
        this.elapsed = 0;
        this.isComplete = false;
        this.onComplete = null;
        this.onStart = null;
    }

    update(deltaTime) {
        this.elapsed += deltaTime;

        if (this.elapsed >= this.duration) {
            this.elapsed = this.duration;
            this.isComplete = true;
            if (this.onComplete) {
                this.onComplete();
            }
        }

        this.apply(this.getProgress());
    }

    getProgress() {
        return this.elapsed / this.duration;
    }

    apply(progress) {
        // Override in subclasses
    }
}

/**
 * Easing functions
 */
const Easing = {
    linear: t => t,
    easeInOutQuad: t => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2,
    easeOutCubic: t => 1 - Math.pow(1 - t, 3),
    easeOutBounce: t => {
        const n1 = 7.5625;
        const d1 = 2.75;
        if (t < 1 / d1) {
            return n1 * t * t;
        } else if (t < 2 / d1) {
            return n1 * (t -= 1.5 / d1) * t + 0.75;
        } else if (t < 2.5 / d1) {
            return n1 * (t -= 2.25 / d1) * t + 0.9375;
        } else {
            return n1 * (t -= 2.625 / d1) * t + 0.984375;
        }
    }
};

/**
 * Piece move animation
 */
class PieceMoveAnimation extends Animation {
    constructor(fromX, fromY, toX, toY, piece, duration = 300) {
        super(duration);
        this.fromX = fromX;
        this.fromY = fromY;
        this.toX = toX;
        this.toY = toY;
        this.piece = piece;
        this.currentX = fromX;
        this.currentY = fromY;
    }

    getProgress() {
        return Easing.easeInOutQuad(this.elapsed / this.duration);
    }

    apply(progress) {
        this.currentX = this.fromX + (this.toX - this.fromX) * progress;
        this.currentY = this.fromY + (this.toY - this.fromY) * progress;
    }

    /**
     * Draw the animating piece
     * @param {CanvasRenderingContext2D} ctx - Canvas context
     * @param {number} size - Square size
     */
    draw(ctx, size) {
        if (this.isComplete) return;

        const x = this.currentX;
        const y = this.currentY;

        ctx.save();
        ctx.globalAlpha = 0.8;

        // Draw shadow
        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        ctx.beginPath();
        ctx.ellipse(
            x + size / 2,
            y + size * 0.85,
            size * 0.3,
            size * 0.1,
            0, 0, Math.PI * 2
        );
        ctx.fill();

        // Draw piece
        GoTTheme.drawPiece(ctx, this.piece.type, this.piece.color, x, y, size);

        ctx.restore();
    }
}

/**
 * Capture animation - pieces exploding/fading
 */
class CaptureAnimation extends Animation {
    constructor(x, y, piece, duration = 400) {
        super(duration);
        this.x = x;
        this.y = y;
        this.piece = piece;
        this.scale = 1;
        this.alpha = 1;
        this.rotation = 0;
        this.particles = this.createParticles();
    }

    createParticles() {
        const particles = [];
        const particleCount = 10;

        for (let i = 0; i < particleCount; i++) {
            const angle = (Math.PI * 2 * i) / particleCount;
            const speed = 2 + Math.random() * 3;
            particles.push({
                x: this.x + 40, // Center of square
                y: this.y + 40,
                vx: Math.cos(angle) * speed,
                vy: Math.sin(angle) * speed,
                size: 3 + Math.random() * 5,
                alpha: 1
            });
        }

        return particles;
    }

    getProgress() {
        return Easing.easeOutCubic(this.elapsed / this.duration);
    }

    apply(progress) {
        this.scale = 1 - progress * 0.3;
        this.alpha = 1 - progress;
        this.rotation = progress * Math.PI * 2;

        // Update particles
        this.particles.forEach(p => {
            p.x += p.vx;
            p.y += p.vy;
            p.alpha = 1 - progress;
        });
    }

    /**
     * Draw the capture animation
     * @param {CanvasRenderingContext2D} ctx - Canvas context
     * @param {number} size - Square size
     */
    draw(ctx, size) {
        if (this.isComplete) return;

        ctx.save();

        // Draw particles
        this.particles.forEach(p => {
            if (p.alpha > 0) {
                ctx.globalAlpha = p.alpha;
                ctx.fillStyle = this.piece.color === 'white' ? '#4a4a4a' : '#4fc3f7';
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
            }
        });

        // Draw fading piece
        ctx.globalAlpha = this.alpha;
        ctx.translate(this.x + size / 2, this.y + size / 2);
        ctx.rotate(this.rotation);
        ctx.scale(this.scale, this.scale);
        ctx.translate(-(this.x + size / 2), -(this.y + size / 2));

        GoTTheme.drawPiece(ctx, this.piece.type, this.piece.color, this.x, this.y, size);

        ctx.restore();
    }
}

/**
 * Check alert animation - screen shake
 */
class CheckAlertAnimation extends Animation {
    constructor(duration = 500) {
        super(duration);
        this.shakeIntensity = 0;
        this.glowIntensity = 0;
    }

    getProgress() {
        return this.elapsed / this.duration;
    }

    apply(progress) {
        // Shake intensity peaks at start and fades
        this.shakeIntensity = Math.max(0, 5 * (1 - progress * 2));
        this.glowIntensity = Math.sin(progress * Math.PI * 4) * (1 - progress);
    }

    /**
     * Get shake offset
     * @returns {Object} {x, y} offset
     */
    getShakeOffset() {
        if (this.isComplete) return { x: 0, y: 0 };

        return {
            x: (Math.random() - 0.5) * this.shakeIntensity,
            y: (Math.random() - 0.5) * this.shakeIntensity
        };
    }

    /**
     * Draw glow effect on king
     * @param {CanvasRenderingContext2D} ctx - Canvas context
     * @param {number} x - King x position
     * @param {number} y - King y position
     * @param {number} size - Square size
     */
    drawGlow(ctx, x, y, size) {
        if (this.isComplete) return;

        const centerX = x + size / 2;
        const centerY = y + size / 2;
        const radius = size * (0.5 + this.glowIntensity * 0.3);

        ctx.save();
        ctx.globalAlpha = 0.3 + this.glowIntensity * 0.2;
        ctx.fillStyle = '#f44336';
        ctx.beginPath();
        ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
    }
}

/**
 * Game over animation
 */
class GameOverAnimation extends Animation {
    constructor(winner, duration = 1000) {
        super(duration);
        this.winner = winner;
        this.alpha = 0;
        this.scale = 0.5;
    }

    getProgress() {
        return Easing.easeOutBounce(this.elapsed / this.duration);
    }

    apply(progress) {
        this.alpha = progress;
        this.scale = 0.5 + progress * 0.5;
    }

    /**
     * Draw game over overlay
     * @param {CanvasRenderingContext2D} ctx - Canvas context
     * @param {number} width - Canvas width
     * @param {number} height - Canvas height
     */
    draw(ctx, width, height) {
        if (this.isComplete) return;

        ctx.save();

        // Darken background
        ctx.fillStyle = `rgba(0, 0, 0, ${this.alpha * 0.7})`;
        ctx.fillRect(0, 0, width, height);

        // Draw message
        ctx.globalAlpha = this.alpha;
        ctx.translate(width / 2, height / 2);
        ctx.scale(this.scale, this.scale);

        ctx.fillStyle = this.winner === 'white' ? '#c9a227' : '#4fc3f7';
        ctx.font = 'bold 48px Cinzel';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        const winnerName = this.winner === 'white' ? 'Noble Houses' : 'White Walkers';
        ctx.fillText(`${winnerName} Win!`, 0, 0);

        ctx.font = '24px MedievalSharp';
        ctx.fillStyle = '#e3f2fd';
        ctx.fillText('Game Over', 0, 50);

        ctx.restore();
    }
}

/**
 * Hover effect animation
 */
class HoverAnimation extends Animation {
    constructor(duration = 200) {
        super(duration);
        this.scale = 1;
        this.direction = 1;
    }

    getProgress() {
        return Math.sin(this.elapsed / this.duration * Math.PI);
    }

    apply(progress) {
        this.scale = 1 + progress * 0.05;
    }

    /**
     * Get current scale
     * @returns {number} Scale factor
     */
    getScale() {
        return this.scale;
    }
}

