    97→
    98→        this.isDragging = true;
    99→        this.dragStartPos = pos;
   100→    }
   101→
   102→    /**
   103→     * Handle touch move
   104→     * @param {TouchEvent} e - Touch event
   105→     */
   106→    handleTouchMove(e) {
   107→        e.preventDefault();
   108→
   109→        if (!this.isDragging) {
   110→            return;
   111→        }
   112→
   113→        const touch = e.touches[0];
   114→        const pos = this.renderer.canvasToBoard(touch.clientX, touch.clientY);
   115→
   116→        if (Position.isValid(pos.row, pos.col)) {
   117→            this.renderer.setHoveredSquare(pos);
   118→            this.renderer.render();
   119→        }
   120→    }
   121→
   122→    /**
   123→     * Handle touch end
   124→     * @param {TouchEvent} e - Touch event
   125→     */
   126→    handleTouchEnd(e) {
   127→        e.preventDefault();
   128→
   129→        if (!this.isDragging || !this.dragStartPos) {
   130→            return;
   131→        }
   132→
   133→        const touch = e.changedTouches[0];
   134→        const pos = this.renderer.canvasToBoard(touch.clientX, touch.clientY);
   135→
   136→        if (Position.isValid(pos.row, pos.col)) {
   137→            this.handleSquareClick(pos);
   138→        }
   139→
   140→        this.isDragging = false;
   141→        this.dragStartPos = null;
   142→    }
   143→
   144→    /**
   145→     * Handle clicking on a square
   146→     * @param {Object} pos - Board position {row, col}
   147→     */
   148→    handleSquareClick(pos) {
   149→        const clickedPiece = this.gameEngine.board.getPieceAt(pos.row, pos.col);
   150→
   151→        // If we have a selected piece, try to move
   152→        if (this.selectedPiece) {
   153→            // Check if clicking on valid move
   154→            const isValidMove = this.renderer.validMoves.some(
   155→                move => move.row === pos.row && move.col === pos.col
   156→            );
   157→
   158→            if (isValidMove) {
   159→                this.executeMove(this.selectedPiece, pos);
   160→                return;
   161→            }
   162→
   163→            // If clicking on own piece, select it instead
   164→            if (clickedPiece && clickedPiece.color === this.gameEngine.currentTurn) {
   165→                this.selectPiece(pos);
   166→                return;
   167→            }
   168→
   169→            // Otherwise, deselect
   170→            this.deselectPiece();
   171→            return;
   172→        }
   173→
   174→        // If no piece selected, try to select one
   175→        if (clickedPiece && clickedPiece.color === this.gameEngine.currentTurn) {
   176→            this.selectPiece(pos);
   177→        }
   178→    }
   179→
   180→    /**
   181→     * Select a piece
   182→     * @param {Object} pos - Position {row, col}
   183→     */
   184→    selectPiece(pos) {
   185→        const piece = this.gameEngine.board.getPieceAt(pos.row, pos.col);
   186→
   187→        if (!piece || piece.color !== this.gameEngine.currentTurn) {
   188→            return;
   189→        }
   190→
   191→        this.selectedPiece = { ...pos, piece };
   192→        this.renderer.setSelectedSquare(pos);
   193→
   194→        // Get and display valid moves
   195→        const validMoves = Rules.getLegalMoves(this.gameEngine.board, pos);
   196→        this.renderer.setValidMoves(validMoves);
   197→
   198→        this.renderer.render();
   199→    }
   200→
   201→    /**
   202→     * Deselect current piece
   203→     */
   204→    deselectPiece() {
   205→        this.selectedPiece = null;
   206→        this.renderer.setSelectedSquare(null);
   207→        this.renderer.setValidMoves([]);
   208→        this.renderer.render();
   209→    }
   210→
   211→    /**
   212→     * Execute a move
   213→     * @param {Object} from - Source position
   214→     * @param {Object} to - Destination position
   215→     */
   216→    async executeMove(from, to) {
   217→        const moveResult = this.gameEngine.makeMove(from, to);
   218→
   219→        if (moveResult.success) {
   220→            this.deselectPiece();
   221→
